int ready_wait(uint64_t timeout) {
  if (!future_.valid())
    return 0;
  uint64_t timeout_sec = timeout / 1000;
  std::chrono::seconds wait_time(1);
  for (;;) {
    // wait for 1 sec and check status
    auto status = future_.wait_for(wait_time);
    if (status == std::future_status::ready)
      break;
    if (0 == timeout_sec--)
      return -1;
  }
  return 0;

